import{_ as i,o as t,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Shared Responsibility","description":"","frontmatter":{"title":"Shared Responsibility","slug":"shared-responsibility"},"headers":[],"relativePath":"account-hub/shared-responsibility.md","filePath":"account-hub/shared-responsibility.md"}'),n={name:"account-hub/shared-responsibility.md"};function s(o,e,c,l,d,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch provides an industry leading mobile linking and measurement platform that unifies user experiences and attribution across devices, platforms, and channels. We understand the inherent risks of operating our <strong>Service</strong> in a digital landscape where cyber attackers are looking for opportunities to compromise data.</p><p>We operate our Service under a shared responsibility model by which the responsibility for certain security and compliance elements is shared between us and our customers. We provide appropriate technical and organizational measures to ensure the security and privacy of the Service infrastructure.</p><p><strong>You are responsible for your implementation of the Service</strong> and configuration of the security, privacy, and retention settings within the Service.</p><p>If you can control a parameter within the Services, then <strong>you are responsible for ensuring it is configured to meet your compliance needs</strong>.</p><p>This shared responsibility model enables us to provide you with a Service that can be configured to empower our most security conscious customers to enhance their end users&#39; experience and improve measurement performance across their business.</p><p>Our commitment to providing a secure experience for our customers works in tandem with your responsibility for adhering to certain standards and practices as a subscriber to the Service as further outlined below.</p><h2 id="access-controls-and-configuration" tabindex="-1">Access controls and configuration <a class="header-anchor" href="#access-controls-and-configuration" aria-label="Permalink to &quot;Access controls and configuration&quot;">​</a></h2><h4 id="branch-s-responsibilities" tabindex="-1">Branch&#39;s responsibilities <a class="header-anchor" href="#branch-s-responsibilities" aria-label="Permalink to &quot;Branch&#39;s responsibilities&quot;">​</a></h4><ul><li>Promote and maintain robust security and privacy measures within the Service to protect the confidentiality, integrity, and availability of data which includes the maintenance and configuration of Branch&#39;s Software Development Kit (SDK), cloud infrastructure, and the operating software deployed on its cloud infrastructure.</li><li>Maintain secure system access for its personnel, including role-based security access, with multi-factor authentication and password access control.</li><li>Provide multiple security controls and settings that can be configured by customers to address their security needs.</li></ul><h4 id="your-responsibilities" tabindex="-1">Your responsibilities <a class="header-anchor" href="#your-responsibilities" aria-label="Permalink to &quot;Your responsibilities&quot;">​</a></h4><ul><li><strong>Implement the Service and configure appropriate controls</strong> in line with Branch&#39;s Documentation, acceptable use guidelines, and industry leading security practices or your own internal security policies.</li><li><strong>Assign proper roles and permissions to authorized users</strong>, along with robust user provisioning processes that incorporate the principle of least privilege, to ensure that authorized users only have the minimum access necessary to perform their pre-specified duties.</li><li><strong>Implement and enforce secure authentication</strong> (e.g., SSO, MFA) on customer-managed interfaces.<br> Maintain and configure your own mobile applications, marketing materials, websites, and other assets or digital properties that you deploy the Service in.</li></ul><h2 id="privacy-and-data-security" tabindex="-1">Privacy and data security <a class="header-anchor" href="#privacy-and-data-security" aria-label="Permalink to &quot;Privacy and data security&quot;">​</a></h2><h4 id="branch-s-responsibilities-1" tabindex="-1">Branch&#39;s responsibilities <a class="header-anchor" href="#branch-s-responsibilities-1" aria-label="Permalink to &quot;Branch&#39;s responsibilities&quot;">​</a></h4><ul><li>Conduct security vulnerability scanning and penetration tests on the cloud environment and employ system monitoring tools to detect system events for suspicious activity.</li><li>Patch and repair flaws within the cloud infrastructure, the operating software deployed on its cloud infrastructure, and the SDK it makes available to customers.</li><li>Maintain a security incident response program that is tested regularly.</li><li>Perform third-party security assessments and audits.</li><li>Protect data from external threats through appropriate cloud security controls including the encryption of data at rest and in transit over public networks.</li><li>Provide an additional level of data protection with field-level encryption for customers utilizing the Advanced Compliance Service.</li><li>Maintain a range of industry standard third-party audit certifications available at <a href="https://www.branch.io/security" target="_blank" rel="noreferrer">https://www.branch.io/security</a>.</li><li>Maintain a documented data privacy statement that describes what data Branch collects, how it is used, and how it is shared available at <a href="https://branch.io/privacy" target="_blank" rel="noreferrer">https://branch.io/privacy</a>.</li><li>Provide routine security awareness and privacy training to Branch personnel.</li><li>Comply with laws and regulations applicable to Branch&#39;s provision of the Service.</li></ul><h4 id="your-responsibilities-1" tabindex="-1">Your responsibilities <a class="header-anchor" href="#your-responsibilities-1" aria-label="Permalink to &quot;Your responsibilities&quot;">​</a></h4><ul><li><strong>Ensure that any data uploaded to the Service complies with applicable laws</strong> and regulations, Branch&#39;s Acceptable Use Policy, and industry best practices.</li><li><strong>Implement internal policies and guidelines designed to protect data</strong> processed through the Service and provide routine security awareness and privacy training to personnel.</li><li><strong>Understand where data may be shared with a third party</strong> through an integration or other optional configuration, and treat such channels or configurations in accordance with your security policies and approved use cases.</li><li><strong>Monitor all activity within your instance</strong> of the Service including timely review of audit logs.</li><li><strong>Notify Branch immediately when you become aware of, or suspect that a security vulnerability exists</strong>, or that a data breach or security incident involving the Service has occurred or is likely to occur.</li><li><strong>Promote the secure deployment and maintenance of all third-party integrations</strong> you configure within the Service and ensure continuous monitoring and incident response on customer and third-party integration assets.</li><li><strong>Maintain and apply security updates</strong>, patches, and fraud detection and prevention measures to your own infrastructure used to access the Service.</li></ul><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>Please visit the pages below for more information about the topics mentioned above.</p><h4 id="branch-help-center" tabindex="-1">Branch Help Center <a class="header-anchor" href="#branch-help-center" aria-label="Permalink to &quot;Branch Help Center&quot;">​</a></h4><ul><li><a href="./quick-start-guide-for-implementing-branch.html">Branch Quick Start Guide</a></li><li><a href="./entity-views-access-controls-overview.html">User Permissions and Management</a></li><li><a href="./best-practices-to-avoid-sending-pii-to-branch.html">Data Privacy</a></li><li><a href="./data-integration-implementation-guide.html">Data Integration Implementation Guide</a></li><li><a href="./data-integration-partners.html">Data Integration Partners</a></li><li><a href="./in-depth-fraud-recommendations.html">Fraud Prevention</a></li><li><a href="./enable-single-sign-on.html">Account Settings</a></li></ul><h4 id="branch-legal-center" tabindex="-1">Branch Legal Center <a class="header-anchor" href="#branch-legal-center" aria-label="Permalink to &quot;Branch Legal Center&quot;">​</a></h4><ul><li><a href="https://legal.branch.io/#third-party-list" target="_blank" rel="noreferrer">Branch Subprocessors</a></li></ul><h4 id="branch-website" tabindex="-1">Branch website <a class="header-anchor" href="#branch-website" aria-label="Permalink to &quot;Branch website&quot;">​</a></h4><ul><li><a href="https://www.branch.io/security/" target="_blank" rel="noreferrer">Branch Security</a></li></ul>',25)])])}const m=i(n,[["render",s]]);export{p as __pageData,m as default};
